const root = $input.first().json;
const headers = root.headers || {};
const secret = headers['x-telegram-bot-api-secret-token'] || headers['X-Telegram-Bot-Api-Secret-Token'];
if (!secret || secret !== $env.TG_WEBHOOK_SECRET) {
  throw new Error('Forbidden: invalid webhook secret');
}

const update = root.body && typeof root.body === 'object' ? root.body : root;
const cb = update.callback_query;
const msg = cb?.message || update.message || {};
const from = cb?.from || update.message?.from || {};
const chat = msg.chat || {};
const data = String(cb?.data || '');

let callbackAction = '';
let pendingLogId = null;
let feedbackLogId = null;
if (data.startsWith('support_yes:')) { callbackAction = 'yes'; pendingLogId = Number(data.split(':')[1]); }
if (data.startsWith('support_no:')) { callbackAction = 'no'; pendingLogId = Number(data.split(':')[1]); }
if (data.startsWith('fb_yes:')) { callbackAction = 'fb_yes'; feedbackLogId = Number(data.split(':')[1]); }
if (data.startsWith('fb_no:')) { callbackAction = 'fb_no'; feedbackLogId = Number(data.split(':')[1]); }

const messageType = (() => {
  const m = update.message;
  if (!m) return 'callback_or_empty';
  if (m.text) return 'text';
  if (m.photo) return 'photo';
  if (m.voice) return 'voice';
  if (m.video) return 'video';
  if (m.document) return 'document';
  if (m.sticker) return 'sticker';
  if (m.audio) return 'audio';
  return 'other';
})();

const MAX_QUESTION_LENGTH = 1000;
const questionTrimmed = String(update.message?.text || '').trim().slice(0, MAX_QUESTION_LENGTH);

return [{
  json: {
    update_type: cb ? 'callback_query' : 'message',
    is_callback: Boolean(cb),
    callback_action: callbackAction,
    pending_log_id: pendingLogId,
    feedback_log_id: feedbackLogId,
    callback_message_text: String(msg.text || ''),
    chat_id: chat.id || 0,
    message_id: msg.message_id || 0,
    user_id: from.id || 0,
    username: from.username || '',
    question: questionTrimmed,
    has_text: Boolean(questionTrimmed),
    is_start: /^\/start(?:\s|$)/i.test(questionTrimmed),
    message_type: messageType
  }
}];

const rows = $input.all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]).filter(Boolean);
const row = rows[0];
if (!row?.id || !row?.question) throw new Error('Pending qa_log row not found.');
return [{ json: row }];

const rows = $input.all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]).filter(Boolean);
const ticket = rows[0];
if (!ticket?.id) throw new Error('Ticket insert did not return id.');
return [{ json: ticket }];

const inputItems = $input.all();
let matches = [];
if (inputItems.length === 1 && Array.isArray(inputItems[0].json)) matches = inputItems[0].json;
else matches = inputItems.map(item => item.json).filter(item => item && item.id !== undefined && item.content);
return [{ json: { length: matches.length, matches, top_similarity: matches[0]?.similarity ?? null, context: matches.map((m, index) => `[chunk ${index + 1}, similarity=${Number(m.similarity || 0).toFixed(4)}]
${m.content}`).join('

---

') } }];

const chatId = $('Route Telegram Update').item.json.chat_id;
const fullText = String($('OpenAI Chat Completions').item.json.choices?.[0]?.message?.content || '');
const raw = $('Supabase Insert qa_log - answered').item.json;
const qaLogId = Array.isArray(raw) ? raw[0]?.id : raw?.id;
const MAX_LEN = 4000;
if (!fullText) return [{ json: { method: 'sendMessage', chat_id: chatId, text: 'Не удалось сформировать ответ.' } }];
const chunks = [];
if (fullText.length <= MAX_LEN) chunks.push(fullText);
else {
  let current = '';
  for (const paragraph of fullText.split('\n\n')) {
    const merged = current ? (current + '\n\n' + paragraph) : paragraph;
    if (merged.length > MAX_LEN) {
      if (current) chunks.push(current);
      if (paragraph.length > MAX_LEN) {
        for (let i = 0; i < paragraph.length; i += MAX_LEN) chunks.push(paragraph.slice(i, i + MAX_LEN));
        current = '';
      } else current = paragraph;
    } else current = merged;
  }
  if (current) chunks.push(current);
}
return chunks.map((text, index) => {
  const json = { method: 'sendMessage', chat_id: chatId, text };
  if (index === chunks.length - 1 && qaLogId) {
    json.reply_markup = { inline_keyboard: [[ { text: '👍', callback_data: 'fb_yes:' + qaLogId }, { text: '👎', callback_data: 'fb_no:' + qaLogId } ]] };
  }
  return { json };
});

const rows = $input.all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]).filter(Boolean);
const row = rows[0];
if (!row?.id) throw new Error('qa_log pending insert did not return id.');
return [{ json: row }];

return [{ json: {
  method: 'sendMessage',
  chat_id: $('Route Telegram Update').item.json.chat_id,
  text: "Не нашёл точного ответа в базе знаний 🤔\nПередать ваш вопрос команде поддержки?",
