const ticket = $('Normalize Confirmed Ticket').item.json;
const user = $('Route Telegram Update').item.json;
if (!adminId || !$env.TELEGRAM_ADMIN_BOT_TOKEN) {
  return [{ json: { method: 'sendMessage', chat_id: '0', text: 'admin notification skipped' } }];
}
const text = "Новый тикет #" + ticket.id + "\nПользователь: " + (user.username ? '@' + user.username : user.user_id) + "\nВопрос: " + ticket.question + "\n\nОтветить: /reply " + ticket.id + " текст ответа";
const safeText = text.length > 4090 ? text.slice(0, 4090) + '...' : text;
return [{ json: { method: 'sendMessage', chat_id: adminId, text: safeText } }];

