else rows = inputItems.map(i => i.json).filter(r => r && r.id !== undefined && r.answer);
const hit = rows[0] || null;
return [{ json: { cache_hit: Boolean(hit), cache_id: hit?.id ?? null, cached_answer: hit?.answer ?? null, cache_similarity: hit?.similarity ?? null } }];

