const raw = $input.first().json;
const allowed = raw === true || raw?.check_rate_limit === true || raw?.allowed === true;
return [{ json: { rate_limit_ok: Boolean(allowed) } }];

const tickets = $input.all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]).filter(t => t && t.id);
let text;
if (tickets.length === 0) {
  text = "У тебя нет открытых тикетов. Напиши вопрос — если не найду ответ, создадим тикет.";
} else {
  text = "📋 Твои открытые тикеты:\n\n" + tickets.map(t => {
    const q = String(t.question || '');
    const shortQ = q.slice(0, 100);
    const date = new Date(t.created_at).toLocaleDateString('ru-RU');
    return '#' + t.id + " от " + date + "\n" + shortQ + (q.length > 100 ? '...' : '');
  }).join("\n\n");
}
return [{ json: { method: 'sendMessage', chat_id: $('Route Telegram Update').item.json.chat_id, text } }];

const originalText = String($('Route Telegram Update').item.json.callback_message_text || '');
const text = originalText ? (originalText + "\n\nСпасибо за оценку!") : "Спасибо за оценку!";
return [{ json: { method: 'editMessageText', chat_id: $('Route Telegram Update').item.json.chat_id, message_id: $('Route Telegram Update').item.json.message_id, text } }];
